const LL LINF = INF * (LL)INF;



const int MAX = 222;



LL C[MAX][MAX];



LL ADD(LL v1, LL v2)

{

	LL res = v1 + v2;

	if (res >= LINF) res = LINF;

	return res;

}



LL MUL(LL v1, LL v2)

{

	double z = v1 * (double)v2;

	if (z >= 2e18) return LINF;

	LL res = v1 * v2;

	if (res >= LINF) res = LINF;

	return res;

}



LL get(int n, int m)

{

	LL res = 0;

	FOR (len, 0, min(n, m) + 1)

	{

		LL a = C[n][len];

		LL b = C[m][len];



		double z = a * (double)b;

		if (z > 2e18)

		{

			res = LINF;

			break;

		}



		res = ADD(res, a * b);

	}



	return res;

}



