{

	vector<int> ans;

	if(n == 1)

	{

		ans.pb(1);

		ans.pb(1);

		return {ans , 1};

	}



	if(n == 2)

	{

		ans.pb(1);

		ans.pb(50);

		ans.pb(50);

		ans.pb(1);



		return {ans , 2};

	}



	vector<int> tmp;

	int F = 0;



	if(n % 2 == 1)

	{

		auto shit = solve(n / 2);

		F = shit.second;

		tmp = shit.first;

	}

	else

	{

		auto shit = solve(n / 2 - 1);

		F = shit.second;

		tmp = shit.first;

	}



	int mx1 = 0 , mx = 0;

	for(auto x : tmp)

	{

		if(x < 50)

			mx1 = max(mx1 , x);

		mx = max(mx , x);

	}



