	if(n % 2 == 0)

	{

		F++;

		ans.pb(mx + 1);

		ans.pb(mx + 1);

	}



	for(int i = ahhh; i < (int)tmp.size(); i++)

		ans.pb(tmp[i]);



	ans.pb(mx1 + 1);



	return {ans , F};

